            saved_only_note_path = tmp_path / "notes" / "saved-only.md"
            corrected_source_path.write_text("# Demo\n\nhello world", encoding="utf-8")
            saved_only_source_path.write_text("# Demo\n\nhello world", encoding="utf-8")

